"use client";

import { useState } from "react";
import Image from "next/image";
import { motion, useReducedMotion } from "motion/react";
import { useTranslations } from "next-intl";
import { Link } from "@/i18n/navigation";
import { MAP_SECTION_IMAGE_ALT, MAP_SECTION_IMAGE_SRC } from "@/lib/map-assets";

const EASE_OUT_CUBIC: [number, number, number, number] = [0.215, 0.61, 0.355, 1];

const LocationVideo = () => (
    <video
        className="w-full h-full object-cover brightness-110 contrast-110"
        src="/babylon/sma-video.mp4"
        width={720}
        height={406}
        muted
        loop
        playsInline
        autoPlay
        preload="metadata"
    />
);

function MapCornerVideo({
    centroLabel,
    centroSub,
    reduceMotion,
}: {
    centroLabel: string;
    centroSub: string;
    reduceMotion: boolean;
}) {
    return (
        <motion.div
            className="absolute -top-4 -right-3 sm:-top-5 sm:-right-4 md:-top-7 md:-right-6 lg:-top-10 lg:-right-14 xl:-top-16 xl:-right-24 w-28 sm:w-36 md:w-48 lg:w-52 xl:w-64 aspect-square lg:aspect-[3/4] z-30 pointer-events-none"
            variants={{
                hidden: reduceMotion ? { opacity: 1, x: 0 } : { opacity: 0, x: 16 },
                visible: {
                    opacity: 1,
                    x: 0,
                    transition: {
                        duration: reduceMotion ? 0 : 0.5,
                        ease: EASE_OUT_CUBIC,
                        delay: reduceMotion ? 0 : 0.22,
                    },
                },
            }}
        >
            <div className="w-full h-full overflow-hidden border-2 border-white shadow-[0_15px_40px_-12px_rgba(0,0,0,0.12)] relative bg-[#222]">
                <LocationVideo />
                <div className="absolute inset-0 bg-gradient-to-t from-[#222]/80 via-transparent to-transparent opacity-80"></div>
                <div className="absolute bottom-2 left-2 sm:bottom-3 sm:left-3 z-10 hidden md:block">
                    <p className="text-white text-[10px] sm:text-xs md:text-sm font-bold leading-tight">{centroLabel}</p>
                    <p className="text-[#E1B19B] text-[8px] sm:text-[10px] uppercase tracking-wide">{centroSub}</p>
                </div>
            </div>
        </motion.div>
    );
}

type LocationProps = {
    sectionId?: string;
    backgroundClassName?: string;
    showIntro?: boolean;
    showProximity?: boolean;
};

